#include <stdio.h>
#include <stdint.h>
int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long x, m, d;
        scanf("%lld %lld %lld", &x, &m, &d);
        long long without_limit = x * m;
        long long with_limit = x + d;
        long long ans = without_limit < with_limit ? without_limit : with_limit;
        printf("%lld\n", ans);
    }
    return 0;
}

